class Solution:
    def isHappy(self, n: int) -> bool:
        def next(x):
            s = 0
            while x:
                x, d = divmod(x, 10)
                s += d * d
            return s
        slow = fast = n
        while True:
            slow = next(slow)
            fast = next(next(fast))
            if fast == 1:
                return True
            if slow == fast:
                return slow == 1

