class Solution {
    int next(int x) {
        int s = 0;
        while (x) { s += (x % 10) * (x % 10); x /= 10; }
        return s;
    }
public:
    bool isHappy(int n) {
        int slow = n, fast = n;
        do {
            slow = next(slow);
            fast = next(next(fast));
            if (fast == 1) return true;
        } while (slow != fast);
        return slow == 1;
    }
};

