static int nextHappy(int x) {
    int s = 0;
    while (x) { int d = x % 10; s += d * d; x /= 10; }
    return s;
}
bool isHappy(int n) {
    int slow = n, fast = n;
    do {
        slow = nextHappy(slow);
        fast = nextHappy(nextHappy(fast));
        if (fast == 1) return true;
    } while (slow != fast);
    return slow == 1;
}
